import React,
{
  useEffect,
  useState
}
from "react";

import
{
  useNavigate,
  useParams
}
from "react-router-dom";

import "./AppraisalForm.css";

export default function AppraisalForm()
{

  const navigate = useNavigate();

  const { id } = useParams();


  /* ===============================
     ROLE BASE ROUTING
  =============================== */
  const loggedUser =
    JSON.parse(
      localStorage.getItem("loggedInUser")
    ) || {};

  const token =
    localStorage.getItem("token");

  const role =
    loggedUser?.role?.toUpperCase();

  const base =
    role === "ADMIN"
      ? "/admin-dashboard"
      : "/employee-dashboard";


  /* ===============================
     STATE
  =============================== */
  const [employees, setEmployees] =
    useState([]);

  const [formData, setFormData] =
    useState({

      employeeName: "",

      department: "",

      period: "Jan 2024 - Dec 2024",

      rating: "",

      status: "Pending"

    });

  const [errors, setErrors] =
    useState({});


  /* ===============================
     SAFE NAME BUILDER
  =============================== */
  const getEmployeeName =
    (emp) =>
    {

      if (!emp)
        return "";

      const first =
        emp.firstName || "";

      const last =
        emp.lastName || "";

      if (first || last)
        return `${first} ${last}`.trim();

      if (emp.name)
        return emp.name;

      if (emp.email)
        return emp.email.split("@")[0];

      return "Employee";

    };


  /* ===============================
     LOAD EMPLOYEES BASED ON ROLE
  =============================== */
  useEffect(() =>
  {

    const loadEmployees =
      async () =>
      {

        try
        {

          /* ADMIN → load all employees */
          if (role === "ADMIN")
          {

            const res =
              await fetch(
                "http://localhost:8080/api/employees",
                {
                  headers:
                  {
                    Authorization:
                      `Bearer ${token}`
                  }
                }
              );

            if (!res.ok)
              throw new Error(
                "Failed to load employees"
              );

            const data =
              await res.json();

            setEmployees(data);

          }


          /* EMPLOYEE → load own profile */
          else
          {

            const res =
              await fetch(
                "http://localhost:8080/api/profile",
                {
                  headers:
                  {
                    Authorization:
                      `Bearer ${token}`
                  }
                }
              );

            if (!res.ok)
              throw new Error(
                "Failed to load profile"
              );

            const data =
              await res.json();

            setEmployees(
              [
                {
                  id: data.id,
                  firstName:
                    data.email
                      ?.split("@")[0],
                  lastName: "",
                  department:
                    data.department
                }
              ]
            );

          }

        }
        catch (err)
        {

          console.error(
            "Employee load error:",
            err
          );

        }

      };

    loadEmployees();

  }, [role, token]);


  /* ===============================
     LOAD APPRAISAL FOR EDIT MODE
  =============================== */
  useEffect(() =>
  {

    if (!id)
      return;

    const loadAppraisal =
      async () =>
      {

        try
        {

          const res =
            await fetch(
              `http://localhost:8080/api/appraisals/${id}`,
              {
                headers:
                {
                  Authorization:
                    `Bearer ${token}`
                }
              }
            );

          if (!res.ok)
            throw new Error();

          const data =
            await res.json();

          setFormData(
          {
            employeeName:
              data.employeeName || "",

            department:
              data.department || "",

            period:
              data.reviewPeriod || "",

            rating:
              data.rating || "",

            status:
              data.status || "Pending"
          });

        }
        catch (err)
        {

          console.error(
            "Appraisal load error:",
            err
          );

        }

      };

    loadAppraisal();

  }, [id, token]);


  /* ===============================
     HANDLE CHANGE
  =============================== */
  const handleChange =
    (e) =>
    {

      const
      {
        name,
        value
      } = e.target;


      if (name === "employeeName")
      {

        const emp =
          employees.find(
            emp =>
              getEmployeeName(emp)
                === value
          );

        setFormData(
        {
          ...formData,

          employeeName: value,

          department:
            emp?.department || ""
        });

        return;

      }


      setFormData(
      {
        ...formData,

        [name]: value
      });

    };


  /* ===============================
     VALIDATION
  =============================== */
  const validate =
    () =>
    {

      let temp = {};

      if (!formData.employeeName)
        temp.employeeName =
          "Employee required";

      if (!formData.rating)
        temp.rating =
          "Rating required";

      else if (
        formData.rating < 0 ||
        formData.rating > 5
      )
        temp.rating =
          "Rating must be between 0 and 5";

      setErrors(temp);

      return Object.keys(temp).length === 0;

    };


  /* ===============================
     SUBMIT
  =============================== */
  const handleSubmit =
    async (e) =>
    {

      e.preventDefault();

      if (!validate())
        return;

      try
      {

        const method =
          id
            ? "PUT"
            : "POST";

        const url =
          id
            ? `http://localhost:8080/api/appraisals/${id}`
            : `http://localhost:8080/api/appraisals`;

        const res =
          await fetch(
            url,
            {
              method,

              headers:
              {
                "Content-Type":
                  "application/json",

                Authorization:
                  `Bearer ${token}`
              },

              body:
                JSON.stringify(
                {
                  employeeName:
                    formData.employeeName,

                  department:
                    formData.department,

                  reviewPeriod:
                    formData.period,

                  rating:
                    parseFloat(
                      formData.rating
                    ),

                  status:
                    formData.status,

                  remarks: "",

                  salaryIncrease: 0
                })
            }
          );

        if (!res.ok)
          throw new Error();

        alert(
          id
            ? "Updated Successfully"
            : "Created Successfully"
        );

        navigate(
          `${base}/appraisal`
        );

      }
      catch (err)
      {

        console.error(
          "Submit error:",
          err
        );

        alert(
          "Operation failed"
        );

      }

    };


  /* ===============================
     UI
  =============================== */
  return
  (

    <div className="appraisal-form-scope">

      <div className="appraisal-form-card">

        <h2>
          {
            id
              ? "Edit Employee Appraisal"
              : "Add Employee Appraisal"
          }
        </h2>


        <form
          className="appraisal-form"
          onSubmit={handleSubmit}
        >


          {/* Employee */}
          <label>
            Employee Name
          </label>

          <select
            name="employeeName"
            value={formData.employeeName}
            onChange={handleChange}
          >

            <option value="">
              Select Employee
            </option>

            {
              employees.map(emp =>
              (
                <option
                  key={emp.id}
                  value={
                    getEmployeeName(emp)
                  }
                >
                  {
                    getEmployeeName(emp)
                  }
                </option>
              ))
            }

          </select>


          {errors.employeeName &&
            <p className="error-text">
              {errors.employeeName}
            </p>
          }


          {/* Department */}
          <label>
            Department
          </label>

          <input
            value={formData.department}
            disabled
          />


          {/* Period */}
          <label>
            Review Period
          </label>

          <input
            name="period"
            value={formData.period}
            onChange={handleChange}
          />


          {/* Rating */}
          <label>
            Rating
          </label>

          <input
            type="number"
            step="0.1"
            name="rating"
            value={formData.rating}
            onChange={handleChange}
          />


          {errors.rating &&
            <p className="error-text">
              {errors.rating}
            </p>
          }


          {/* Status */}
          <label>
            Status
          </label>

          <select
            name="status"
            value={formData.status}
            onChange={handleChange}
          >

            <option>
              Pending
            </option>

            <option>
              Approved
            </option>

            <option>
              Rejected
            </option>

          </select>


          {/* Buttons */}
          <div className="appraisal-btn-row">

            <button
              type="submit"
              className="appraisal-save-btn"
            >
              Save
            </button>

            <button
              type="button"
              className="appraisal-cancel-btn"
              onClick={() =>
                navigate(
                  `${base}/appraisal`
                )
              }
            >
              Cancel
            </button>

          </div>

        </form>

      </div>

    </div>

  );

}
